SELECT
	COUNT(*)
FROM
	BOOKDREAM_REQUEST
WHERE
	r_state >= 0

AND	user_no = #{user_no}


AND	r_name = #{r_name}


AND	store_no = #{store_no}



#{i}




#{i}



AND	${search_type} LIKE '%' || #{search_text} || '%'

${pagingTop} SELECT r_no, r_src, user_no, user_id, store_no, co_no, r_isbn, r_title, r_author, r_price, r_pay_type, r_pay, r_image, r_publisher, r_pubdate, r_name, r_tel, r_zip, r_addr, r_email, r_state, r_calc, r_payed, r_return_close, r_return, r_refund, r_created, r_updated, (select code_name from cms_code where homepage_id='h3' and group_id = 'H0006' and code_id = r_state) as r_state_nm, decode(r_src, 'andong', '안동', 'yongsang', '용상', '풍산') as r_src_nm , decode(length(r_hp), 10, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 3) || '-' || substr(r_hp, 7, 4), 11, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 4) || '-' || substr(r_hp, 8, 4), r_hp) as r_hp FROM BOOKDREAM_REQUEST WHERE r_state >= 0
AND user_no = #{user_no}
AND r_name = #{r_name}
AND store_no = #{store_no}
#{i}
#{i}
AND ${search_type} LIKE '%' || #{search_text} || '%'
ORDER BY r_no desc ${pagingBottom}

SELECT COUNT(*) FROM BOOKDREAM_REQUEST WHERE r_state >= -100
AND user_no = #{user_no}
#{i}
#{i}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND ${search_date} BETWEEN TO_DATE(#{start_date}, 'YYYY-MM-DD') AND TO_DATE(#{end_date}, 'YYYY-MM-DD')+1

${pagingTop} SELECT r_no, r_src, user_no, user_id, store_no, co_no, r_isbn, r_title, r_author, r_price, r_pay_type, r_pay, r_image, r_publisher, r_pubdate, r_name, r_tel, r_zip, r_addr, r_email, r_state, r_calc, r_payed, r_return_close, r_return, r_refund, r_created, r_updated , decode(length(r_hp), 10, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 3) || '-' || substr(r_hp, 7, 4), 11, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 4) || '-' || substr(r_hp, 8, 4), r_hp) as r_hp, (select code_name from cms_code where homepage_id='h3' and group_id = 'H0005' and code_id = store_no) as storeCode FROM BOOKDREAM_REQUEST WHERE r_state >= -100
AND user_no = #{user_no}
#{i}
#{i}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND ${search_date} BETWEEN TO_DATE(#{start_date}, 'YYYY-MM-DD') AND TO_DATE(#{end_date}, 'YYYY-MM-DD')+1
ORDER BY ${sortField} ${sortType} nulls last ${pagingBottom}

SELECT r_no, r_src, user_no, user_id, store_no, co_no, r_isbn, r_isbn as isbn, r_title, r_author, r_price, r_pay_type, r_pay, r_image, r_publisher, substr(r_pubdate, 1, 4) as r_pubdate, r_name, r_tel, r_zip, r_addr, r_email, r_state, r_calc, r_payed, r_return_close, r_return as c_name, r_refund, r_created as a_name, r_updated , decode(length(r_hp), 10, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 3) || '-' || substr(r_hp, 7, 4), 11, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 4) || '-' || substr(r_hp, 8, 4), r_hp) as r_hp, (select code_name from cms_code where homepage_id='h3' and group_id = 'H0005' and code_id = store_no) as storeCode FROM BOOKDREAM_REQUEST WHERE r_state >= -100
AND user_no = #{user_no}
#{i}
#{i}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND ${search_date} BETWEEN TO_DATE(#{start_date}, 'YYYY-MM-DD') AND TO_DATE(#{end_date}, 'YYYY-MM-DD')+1
ORDER BY ${sortField} ${sortType} nulls last

SELECT r_no, r_src, user_no, user_id, store_no, co_no, r_isbn, r_title, r_author, r_price, r_pay_type, r_pay, r_image, r_publisher, r_pubdate, r_name, r_tel, r_zip, r_addr, r_email, r_state, r_calc, r_payed, r_return_close, r_return, r_refund, r_created, r_updated , decode(length(r_hp), 10, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 3) || '-' || substr(r_hp, 7, 4), 11, substr(r_hp, 0, 3) || '-' || substr(r_hp, 4, 4) || '-' || substr(r_hp, 8, 4), r_hp) as r_hp FROM BOOKDREAM_REQUEST WHERE r_isbn = #{r_isbn}
AND user_no = #{user_no}
ORDER BY r_no

mapper.update:
UPDATE
	BOOKDREAM_REQUEST
SET
	r_updated = SYSDATE
	,r_state = #{r_state}
	,r_hp = #{r_hp}
	,r_email = #{r_email}


	, r_pay = #{r_pay}


	, r_pay_type = #{r_pay_type}

	, r_payed = SYSDATE
	, r_return_close = SYSDATE + 14


	, r_return = SYSDATE


	, r_refund = SYSDATE


	, r_calc = SYSDATE

WHERE
	r_no = #{r_no}

UPDATE BOOKDREAM_STORE SET s_name = #{s_name}, s_tel = #{s_tel}, s_owner = #{s_owner}, s_updated = SYSDATE
,s_pw = #{s_pw}
WHERE s_no = #{s_no}
